/*
 * ultrasonic_levitation.ino — Acoustic Levitation Demo
 *
 * Elements:
 *   1. Timer1 (OC1A/OC1B on D9/D10) — 40 kHz differential drive
 *   2. L298N IN1=D9, IN2=D10        — push-pull transducer drive (12 V)
 *   3. Rotary Encoder KY-040        — frequency tuning ±100 Hz/detent
 *   4. SSD1306 OLED                 — frequency + ON/OFF display
 *   5. Arduino Uno R3               — Timer1 CTC + complementary outputs
 *
 * Physics:
 *   Standing-wave nodes occur at λ/2 intervals above transducer.
 *   At 40 kHz in air (v≈343 m/s): λ ≈ 8.6 mm → node every ~4.3 mm.
 *   Particles are trapped at pressure nodes (not antinodes).
 */

#include <Wire.h>
#include <Adafruit_SSD1306.h>
#include <EEPROM.h>
#include <avr/interrupt.h>

// --- Pins (Timer1 OC outputs) ---
#define OC1A_PIN  9   // IN1 of L298N half-bridge
#define OC1B_PIN 10   // IN2 (complementary)
#define ENA_PIN   6   // L298N enable (HIGH = active)
#define ENC_CLK   2
#define ENC_DT    4
#define ENC_SW    3

// --- Frequency range ---
#define FREQ_MIN  37000UL
#define FREQ_MAX  43000UL
#define FREQ_DEF  40000UL
#define FREQ_STEP   100UL

// --- EEPROM ---
#define EE_FREQ 0  // uint32_t

// --- State ---
uint32_t freq_hz  = FREQ_DEF;
bool     output_on = false;

Adafruit_SSD1306 oled(128, 64, &Wire, -1);

volatile int  enc_d = 0;
volatile bool enc_p = false;
void ICACHE_RAM_ATTR isr_clk() { enc_d += digitalRead(ENC_DT) ? -1 : 1; }
void ICACHE_RAM_ATTR isr_sw()  { enc_p = true; }

void set_freq(uint32_t f) {
  // Timer1 Phase-Correct PWM, TOP = ICR1
  // f_pwm = F_CPU / (2 × prescaler × ICR1) → ICR1 = F_CPU / (2 × 8 × f)
  uint16_t icr = (uint16_t)(F_CPU / (2UL * 8UL * f)) - 1;
  ICR1   = icr;
  OCR1A  = icr / 2;  // 50 % duty
  OCR1B  = icr / 2;
}

void enable_output(bool on) {
  output_on = on;
  if (on) {
    // OC1A normal, OC1B inverted (complementary)
    TCCR1A = (1<<COM1A1) | (1<<COM1B1) | (1<<COM1B0) | (1<<WGM11);
    TCCR1B = (1<<WGM13)  | (1<<CS11);  // Phase-correct PWM, prescaler=8
    digitalWrite(ENA_PIN, HIGH);
  } else {
    TCCR1A = 0; TCCR1B = 0;
    digitalWrite(OC1A_PIN, LOW);
    digitalWrite(OC1B_PIN, LOW);
    digitalWrite(ENA_PIN, LOW);
  }
}

void draw_oled() {
  oled.clearDisplay();
  oled.setTextColor(SSD1306_WHITE);
  oled.setTextSize(2);
  oled.setCursor(0, 4);
  oled.printf("%.1f kHz", freq_hz / 1000.0f);
  oled.setTextSize(1);
  oled.setCursor(0, 32); oled.printf("Output: %s", output_on ? "ON" : "OFF");
  oled.setCursor(0, 44); oled.print("[Encoder: tune freq]");
  oled.setCursor(0, 54); oled.print("[Press:   on/off   ]");
  oled.display();
}

void setup() {
  Serial.begin(115200);
  Wire.begin();

  oled.begin(SSD1306_SWITCHCAPVCC, 0x3C);
  oled.clearDisplay(); oled.display();

  // Load saved frequency
  uint32_t saved;
  EEPROM.get(EE_FREQ, saved);
  if (saved >= FREQ_MIN && saved <= FREQ_MAX) freq_hz = saved;

  pinMode(OC1A_PIN, OUTPUT); pinMode(OC1B_PIN, OUTPUT);
  pinMode(ENA_PIN, OUTPUT);  digitalWrite(ENA_PIN, LOW);
  pinMode(ENC_CLK, INPUT_PULLUP); pinMode(ENC_DT, INPUT_PULLUP); pinMode(ENC_SW, INPUT_PULLUP);
  attachInterrupt(digitalPinToInterrupt(ENC_CLK), isr_clk, FALLING);
  attachInterrupt(digitalPinToInterrupt(ENC_SW),  isr_sw,  FALLING);

  set_freq(freq_hz);
  draw_oled();
  Serial.println(F("Ultrasonic levitation demo ready."));
  Serial.printf("Initial freq: %lu Hz\n", freq_hz);
}

void loop() {
  noInterrupts(); int d = enc_d; enc_d = 0; bool p = enc_p; enc_p = false; interrupts();

  if (d != 0) {
    freq_hz = constrain(freq_hz + (long)d * FREQ_STEP, FREQ_MIN, FREQ_MAX);
    set_freq(freq_hz);
    EEPROM.put(EE_FREQ, freq_hz);
    Serial.printf("freq=%lu Hz\n", freq_hz);
  }
  if (p) enable_output(!output_on);

  static unsigned long last_oled = 0;
  if (millis() - last_oled >= 500UL) {
    last_oled = millis();
    draw_oled();
  }
}
